// Verify all key files use codebert with 768 dimensions
const { GSDKnowledgeSync } = require('./index.js');
const sync1 = new GSDKnowledgeSync();

console.log('=== index.js ===');
console.log('vectorName:', sync1.vectorName, '(expected: codebert-768)');
console.log('embeddingDimensions:', sync1.embeddingDimensions, '(expected: 768)');
console.log('embeddingModel:', sync1.embeddingModel, '(expected: Xenova/codebert-base)');

const { GSDKnowledgeSync: TemplateSync } = require('./src/gsd-qdrant-template.js');
const sync2 = new TemplateSync();

console.log('\\n=== gsd-qdrant-template.js ===');
console.log('vectorName:', sync2.vectorName, '(expected: codebert-768)');
console.log('embeddingDimensions:', sync2.embeddingDimensions, '(expected: 768)');
console.log('embeddingModel:', sync2.embeddingModel, '(expected: Xenova/codebert-base)');

// Test embedding on real code snippet
const testCode = 'async function authenticate(req, res, next) { const token = req.headers.authorization?.split(\" \")[1]; if (!token) return res.status(401).json({error: \"Unauthorized\"}); try { const decoded = jwt.verify(token, process.env.JWT_SECRET); req.user = decoded; next(); } catch(e) { return res.status(403).json({error: \"Invalid token\"}); } }';

Promise.all([
  sync1.embedText(testCode),
  sync2.embedText(testCode)
]).then(([vec1, vec2]) => {
  console.log('\\n=== Embedding Test ===');
  console.log('index.js vector length:', vec1.length, '(expected: 768)');
  console.log('template vector length:', vec2.length, '(expected: 768)');

  // Verify vectors are normalized (cosine distance compatible)
  const norm1 = Math.sqrt(vec1.reduce((s,v) => s + v*v, 0));
  const norm2 = Math.sqrt(vec2.reduce((s,v) => s + v*v, 0));
  console.log('index.js vector norm:', norm1.toFixed(6), '(expected: ~1.0 for normalized)');
  console.log('template vector norm:', norm2.toFixed(6), '(expected: ~1.0 for normalized)');

  // Verify vectors are different from placeholder (which would be hash-based)
  const diff = vec1.reduce((s,v,i) => s + Math.abs(v - vec2[i]), 0);
  console.log('Vector difference:', diff.toFixed(6), '(should be > 0, same model produces same embeddings)');

  if (vec1.length === 768 && vec2.length === 768 && norm1 > 0.9 && norm2 > 0.9) {
    console.log('\\n✅ ALL CHECKS PASSED — codebert integration complete!');
  } else {
    console.error('\\n❌ SOME CHECKS FAILED');
    process.exit(1);
  }
}).catch(err => {
  console.error('❌ Embedding test failed:', err.message);
  process.exit(1);
});
